SELECT id, user_id, target_id, create_time
FROM user_follow
WHERE user_id = #{userId} AND target_id = #{targetId}

SELECT id, user_id, target_id, create_time
FROM user_follow
WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT id, user_id, target_id, create_time
FROM user_follow
WHERE target_id = #{targetId}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}
